let workflow = $json;

// If AI wrapped JSON as string inside "output"
if (workflow.output && typeof workflow.output === "string") {
  workflow = JSON.parse(workflow.output);
}

// Ensure required root fields
workflow.active = workflow.active ?? false;
workflow.settings = workflow.settings ?? {};
workflow.versionId = workflow.versionId ?? "1";

// Build ID → Name map
const idToName = {};
workflow.nodes.forEach(n => {
  idToName[n.id] = n.name;
});

// --- FIX IF CONDITIONS ---
workflow.nodes.forEach(node => {
  if (node.type === "n8n-nodes-base.if" && node.parameters?.conditions) {
    const cond = node.parameters.conditions;

    // Convert boolean → string automatically
    if (cond.boolean) {
      cond.string = cond.boolean;
      delete cond.boolean;
    }

    // Force correct structure
    if (cond.string && Array.isArray(cond.string)) {
      cond.string = cond.string.map(c => ({
        value1: c.value1 || c.property || "",
        operation: c.operation || "equal",
        value2: c.value2 || ""
      }));
    }
  }
});

// --- FIX CONNECTIONS ---
const newConnections = {};

Object.keys(workflow.connections || {}).forEach(key => {
  const fromName = idToName[key] || key;
  const originalMain = workflow.connections[key].main || [];

  newConnections[fromName] = { main: [] };

  // Force 2D structure
  const branches = Array.isArray(originalMain[0])
    ? originalMain
    : originalMain.map(b => [b]);

  branches.forEach((branch, branchIndex) => {
    newConnections[fromName].main[branchIndex] = [];

    branch.forEach(conn => {
      newConnections[fromName].main[branchIndex].push({
        node: idToName[conn.node] || conn.node,
        type: "main",
        index: 0
      });
    });
  });
});

workflow.connections = newConnections;

return [{ json: workflow }];

let workflow = $json;

// If wrapped inside array
if (Array.isArray(workflow)) {
  workflow = workflow[0];
}

// If wrapped inside "output" string
if (workflow.output && typeof workflow.output === "string") {
  workflow = JSON.parse(workflow.output);
}

// Remove Make-specific fields and unstable fields
workflow.nodes.forEach(node => {
  if (node.parameters && node.parameters.__IMTCONN__) {
    delete node.parameters.__IMTCONN__;
  }

  // Remove typeVersion to avoid version mismatch errors
  if (node.typeVersion) {
    delete node.typeVersion;
  }
});

// Remove optional fields that can cause import mismatch
delete workflow.active;
delete workflow.settings;
delete workflow.versionId;

// Ensure connections exist
workflow.connections = workflow.connections || {};

// Return CLEAN object (not array)
return [
  {
    json: workflow
  }
];
